<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Ubuntu Desktop</title>
<style>
  *, *::before, *::after { margin: 0; padding: 0; box-sizing: border-box; }

  body {
    overflow: hidden;
    font-family: 'Segoe UI', Cantarell, Ubuntu, sans-serif;
    user-select: none;
    height: 100vh;
    width: 100vw;
  }

  #desktop {
    width: 100vw;
    height: 100vh;
    background: linear-gradient(135deg, #1a1a2e 0%, #16213e 30%, #0f3460 60%, #1a1a2e 100%);
    position: relative;
    overflow: hidden;
  }

  #desktop::before {
    content: '';
    position: absolute;
    top: 0; left: 0; right: 0; bottom: 0;
    background:
      radial-gradient(ellipse at 20% 50%, rgba(121, 60, 160, 0.15) 0%, transparent 60%),
      radial-gradient(ellipse at 80% 20%, rgba(237, 100, 166, 0.1) 0%, transparent 50%),
      radial-gradient(ellipse at 50% 80%, rgba(59, 130, 246, 0.1) 0%, transparent 50%);
    pointer-events: none;
  }

  /* ── Taskbar / Dock ── */
  #taskbar {
    position: absolute;
    bottom: 0;
    left: 0;
    right: 0;
    height: 56px;
    background: rgba(30, 30, 46, 0.92);
    backdrop-filter: blur(20px);
    -webkit-backdrop-filter: blur(20px);
    border-top: 1px solid rgba(255,255,255,0.08);
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 8px;
    z-index: 9999;
    padding: 0 16px;
  }

  .dock-btn {
    width: 44px;
    height: 44px;
    border-radius: 12px;
    border: none;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    transition: all 0.2s ease;
    position: relative;
    background: rgba(255,255,255,0.06);
    color: #e0e0e0;
    font-size: 20px;
  }

  .dock-btn:hover {
    background: rgba(255,255,255,0.14);
    transform: scale(1.08);
  }

  .dock-btn:active {
    transform: scale(0.95);
  }

  .dock-btn.active::after {
    content: '';
    position: absolute;
    bottom: -4px;
    left: 50%;
    transform: translateX(-50%);
    width: 6px;
    height: 6px;
    border-radius: 50%;
    background: #e95420;
    box-shadow: 0 0 6px #e95420;
  }

  .dock-btn svg { width: 24px; height: 24px; }

  .dock-label {
    position: absolute;
    top: -32px;
    left: 50%;
    transform: translateX(-50%);
    background: rgba(30,30,46,0.95);
    color: #ddd;
    font-size: 11px;
    padding: 3px 8px;
    border-radius: 4px;
    white-space: nowrap;
    opacity: 0;
    pointer-events: none;
    transition: opacity 0.15s;
  }

  .dock-btn:hover .dock-label { opacity: 1; }

  /* ── Top Bar ── */
  #topbar {
    position: absolute;
    top: 0; left: 0; right: 0;
    height: 28px;
    background: rgba(20, 20, 30, 0.85);
    backdrop-filter: blur(12px);
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0 16px;
    color: #ccc;
    font-size: 13px;
    z-index: 9998;
    border-bottom: 1px solid rgba(255,255,255,0.05);
  }

  #topbar .clock { font-weight: 500; letter-spacing: 0.3px; }

  /* ── Windows ── */
  .window {
    position: absolute;
    min-width: 360px;
    min-height: 240px;
    background: rgba(32, 32, 48, 0.96);
    backdrop-filter: blur(16px);
    border-radius: 12px;
    border: 1px solid rgba(255,255,255,0.1);
    box-shadow:
      0 8px 32px rgba(0,0,0,0.5),
      0 2px 8px rgba(0,0,0,0.3),
