    flex-direction: column;
    overflow: hidden;
    transition: box-shadow 0.2s;
  }

  .window.focused {
    box-shadow:
      0 12px 48px rgba(0,0,0,0.6),
      0 4px 12px rgba(0,0,0,0.4),
