    border-color: rgba(255,255,255,0.15);
  }

  .window.hidden { display: none; }

  .win-titlebar {
    height: 38px;
    background: rgba(40, 40, 58, 0.9);
    display: flex;
    align-items: center;
    padding: 0 12px;
    cursor: grab;
    flex-shrink: 0;
    border-bottom: 1px solid rgba(255,255,255,0.06);
  }

  .win-titlebar:active { cursor: grabbing; }

  .win-title {
