    padding: 4px 12px;
    border-radius: 6px;
    cursor: pointer;
    font-size: 12px;
    transition: background 0.15s;
  }

  #files-up:hover { background: rgba(255,255,255,0.15); }
  #files-up:disabled { opacity: 0.3; cursor: default; }

  #files-path {
    flex: 1;
    background: rgba(0,0,0,0.3);
    border: 1px solid rgba(255,255,255,0.08);
    color: #aaa;
    padding: 4px 10px;
    border-radius: 6px;
    font-size: 12px;
    font-family: 'Cascadia Code', 'Fira Code', monospace;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
  }

  .files-content {
    padding: 12px;
    display: flex;
    flex-wrap: wrap;
    gap: 8px;
    align-content: flex-start;
  }

  .fs-item {
    display: flex;
    flex-direction: column;
    align-items: center;
    padding: 10px 8px;
    border-radius: 8px;
    cursor: pointer;
    transition: background 0.15s;
    min-width: 80px;
    text-align: center;
    color: #ddd;
    font-size: 12px;
  }

  .fs-item:hover { background: rgba(255,255,255,0.08); }
  .fs-item:active { background: rgba(255,255,255,0.12); }

  .fs-icon {
    font-size: 32px;
    margin-bottom: 6px;
    line-height: 1;
  }

  .fs-name {
    word-break: break-all;
    max-width: 80px;
    line-height: 1.3;
  }

  /* ── Notepad App ── */
  .notepad-toolbar {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 6px 10px;
    background: rgba(36, 36, 52, 0.8);
    border-bottom: 1px solid rgba(255,255,255,0.06);
  }

  #new-tab {
    background: rgba(255,255,255,0.08);
    border: 1px solid rgba(255,255,255,0.1);
    color: #ccc;
    padding: 4px 10px;
    border-radius: 6px;
    cursor: pointer;
    font-size: 12px;
    transition: background 0.15s;
  }

  #new-tab:hover { background: rgba(255,255,255,0.15); }

  #tabs {
    display: flex;
    gap: 2px;
    padding: 6px 10px 0;
    background: rgba(30, 30, 44, 0.9);
    border-bottom: 1px solid rgba(255,255,255,0.06);
    overflow-x: auto;
    flex-shrink: 0;
  }

  .tab {
    padding: 6px 14px;
    background: rgba(255,255,255,0.04);
    border: 1px solid rgba(255,255,255,0.06);
    border-bottom: none;
    border-radius: 8px 8px 0 0;
    color: #999;
