  .tab:hover { background: rgba(255,255,255,0.08); color: #ccc; }

  .tab.active {
    background: rgba(32, 32, 48, 0.96);
    color: #e0e0e0;
    border-color: rgba(255,255,255,0.1);
  }

  .tab-close {
    width: 16px;
    height: 16px;
    border-radius: 50%;
    border: none;
    background: transparent;
    color: #888;
    cursor: pointer;
    font-size: 14px;
    line-height: 1;
    display: flex;
    align-items: center;
    justify-content: center;
