  .tab-close:hover { background: rgba(233, 84, 32, 0.6); color: #fff; }

  #editor {
    flex: 1;
    width: 100%;
    background: rgba(28, 28, 42, 0.95);
    color: #d4d4d4;
    border: none;
    padding: 12px;
    font-family: 'Cascadia Code', 'Fira Code', 'Consolas', monospace;
