                  'vacation': {
                    type: 'dir',
                    children: {
                      'IMG_001.jpg': { type: 'file', size: '3.2M' },
                      'IMG_002.jpg': { type: 'file', size: '2.9M' },
                      'IMG_003.jpg': { type: 'file', size: '3.5M' }
                    }
                  }
                }
              },
              '.bashrc': { type: 'file', size: '4K' },
              '.profile': { type: 'file', size: '2K' },
              'readme.txt': { type: 'file', size: '1K' }
            }
          }
        }
      },
      'usr': {
        type: 'dir',
        children: {
          'bin': {
            type: 'dir',
            children: {
              'vim': { type: 'file', size: '28K' },
              'git': { type: 'file', size: '18K' }
            }
          },
          'share': {
            type: 'dir',
            children: {
              'applications': {
                type: 'dir',
                children: {
                  'firefox.desktop': { type: 'file', size: '1K' },
                  'code.desktop': { type: 'file', size: '1K' }
                }
              },
              'themes': {
                type: 'dir',
                children: {
                  'Adwaita': { type: 'dir', children: {} }
                }
              }
            }
          },
          'lib': {
            type: 'dir',
            children: {
              'libssl.so': { type: 'file', size: '512K' },
              'libcurl.so': { type: 'file', size: '256K' }
            }
          }
        }
      },
      'var': {
        type: 'dir',
        children: {
          'log': {
            type: 'dir',
            children: {
              'syslog': { type: 'file', size: '1.2M' },
              'auth.log': { type: 'file', size: '800K' },
              'kern.log': { type: 'file', size: '600K' }
            }
          },
          'www': {
            type: 'dir',
            children: {
              'html': {
                type: 'dir',
                children: {
                  'index.html': { type: 'file', size: '4K' },
                  'style.css': { type: 'file', size: '2K' }
                }
              }
            }
