};

let currentPath = '/';

function getNode(path) {
  if (path === '/') return FS['/'];
  const parts = path.split('/').filter(Boolean);
  let node = FS['/'];
  for (const p of parts) {
    if (node.children && node.children[p]) {
      node = node.children[p];
    } else {
      return null;
    }
  }
  return node;
}

function renderFiles() {
  const node = getNode(currentPath);
  const container = document.getElementById('files-content');
  const pathEl = document.getElementById('files-path');
  const upBtn = document.getElementById('files-up');

  pathEl.textContent = currentPath;
  upBtn.disabled = currentPath === '/';

  container.innerHTML = '';

  if (!node || !node.children) return;

  const entries = Object.entries(node.children);
  // Sort: directories first, then files, alphabetically
  entries.sort((a, b) => {
    const aIsDir = a[1].type === 'dir' ? 0 : 1;
    const bIsDir = b[1].type === 'dir' ? 0 : 1;
    if (aIsDir !== bIsDir) return aIsDir - bIsDir;
    return a[0].localeCompare(b[0]);
  });

  for (const [name, entry] of entries) {
    const item = document.createElement('div');
    item.className = 'fs-item';
    item.textContent = '';

    const icon = document.createElement('div');
    icon.className = 'fs-icon';

    const nameEl = document.createElement('div');
    nameEl.className = 'fs-name';
    nameEl.textContent = name;

    if (entry.type === 'dir') {
      icon.textContent = '📁';
      item.ondblclick = () => {
        currentPath = currentPath === '/' ? '/' + name : currentPath + '/' + name;
        renderFiles();
      };
    } else {
      const ext = name.split('.').pop().toLowerCase();
      const icons = {
        txt: '📄', md: '📄', pdf: '📕', sh: '⚙️',
        jpg: '🖼️', png: '🖼️', gz: '📦', tar: '📦',
        html: '🌐', css: '🎨', js: '📜',
        log: '📋', conf: '⚙️', desktop: '🖥️',
        so: '🔧', py: '🐍',
      };
      icon.textContent = icons[ext] || '📄';
    }

    item.appendChild(icon);
    item.appendChild(nameEl);
    container.appendChild(item);
  }
}

function navigateUp() {
  if (currentPath === '/') return;
  const parts = currentPath.split('/').filter(Boolean);
  parts.pop();
  currentPath = parts.length === 0 ? '/' : '/' + parts.join('/');
  renderFiles();
}

// ─── Notepad / Tabs ───
const STORAGE_KEY = 'ubuntu_notepad_tabs';

let tabs = [];
let activeTabId = null;

function generateId() {
  return 'tab_' + Date.now() + '_' + Math.random().toString(36).substr(2, 6);
}

function loadTabs() {
  try {
    const data = localStorage.getItem(STORAGE_KEY);
    if (data) {
      const parsed = JSON.parse(data);
      tabs = parsed.tabs || [];
      activeTabId = parsed.activeTabId || null;
    }
  } catch(e) {
    tabs = [];
    activeTabId = null;
  }
  if (tabs.length === 0) {
    const t = { id: generateId(), title: 'Untitled', content: '' };
    tabs.push(t);
    activeTabId = t.id;
  }
  if (!tabs.find(t => t.id === activeTabId)) {
    activeTabId = tabs.length > 0 ? tabs[0].id : null;
  }
}

function saveTabs() {
  try {
    localStorage.setItem(STORAGE_KEY, JSON.stringify({
      tabs: tabs,
      activeTabId: activeTabId
    }));
  } catch(e) {}
}

function renderTabs() {
  const container = document.getElementById('tabs');
  container.innerHTML = '';

  for (const tab of tabs) {
    const el = document.createElement('div');
    el.className = 'tab' + (tab.id === activeTabId ? ' active' : '');
    el.innerHTML = `<span>${tab.title}</span><button class="tab-close" data-tab-id="${tab.id}">×</button>`;

    el.addEventListener('click', (e) => {
      if (e.target.classList.contains('tab-close')) {
        closeTab(e.target.dataset.tabId);
        return;
      }
      switchTab(tab.id);
    });

    container.appendChild(el);
  }

  const activeTab = tabs.find(t => t.id === activeTabId);
  const editor = document.getElementById('editor');
  if (activeTab) {
    editor.value = activeTab.content;
  } else {
    editor.value = '';
  }
}

function switchTab(id) {
  // Save current tab content
  const current = tabs.find(t => t.id === activeTabId);
  if (current) {
    current.content = document.getElementById('editor').value;
  }
  activeTabId = id;
  renderTabs();
  saveTabs();
}

function createNewTab() {
  // Save current
  const current = tabs.find(t => t.id === activeTabId);
  if (current) {
    current.content = document.getElementById('editor').value;
  }

  const t = { id: generateId(), title: 'Untitled', content: '' };
  tabs.push(t);
  activeTabId = t.id;
  renderTabs();
  saveTabs();
}

function closeTab(id) {
  const idx = tabs.findIndex(t => t.id === id);
  if (idx === -1) return;

  // Save current editor content
  const current = tabs.find(t => t.id === activeTabId);
  if (current) {
    current.content = document.getElementById('editor').value;
  }

  tabs.splice(idx, 1);

  if (tabs.length === 0) {
    const t = { id: generateId(), title: 'Untitled', content: '' };
    tabs.push(t);
    activeTabId = t.id;
  } else if (activeTabId === id) {
    activeTabId = tabs[Math.min(idx, tabs.length - 1)].id;
  }

  renderTabs();
  saveTabs();
}

// Save on input
document.getElementById('editor').addEventListener('input', function() {
  const active = tabs.find(t => t.id === activeTabId);
  if (active) {
    active.content = this.value;
    saveTabs();
  }
});

