// ─── Draggable Windows ───
let dragState = null;

document.querySelectorAll('.win-titlebar').forEach(titlebar => {
  titlebar.addEventListener('mousedown', (e) => {
    if (e.target.classList.contains('win-ctrl-btn')) return;
    const win = titlebar.closest('.window');
    focusWindow(win);

    const rect = win.getBoundingClientRect();
    dragState = {
      win: win,
      offsetX: e.clientX - rect.left,
      offsetY: e.clientY - rect.top
    };
    e.preventDefault();
  });
});

document.addEventListener('mousemove', (e) => {
  if (!dragState) return;
  const { win, offsetX, offsetY } = dragState;
  let x = e.clientX - offsetX;
  let y = e.clientY - offsetY;
  // Keep within viewport
  x = Math.max(0, Math.min(x, window.innerWidth - 100));
  y = Math.max(28, Math.min(y, window.innerHeight - 56 - 40));
  win.style.left = x + 'px';
  win.style.top = y + 'px';
});

document.addEventListener('mouseup', () => {
  dragState = null;
});

// Click on window to focus
document.querySelectorAll('.window').forEach(win => {
  win.addEventListener('mousedown', () => focusWindow(win));
});

